const e={configEditor:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Lee la configuración en vivo de tu impresora directamente desde Moonraker — cada archivo, analizado en secciones y parámetros, con los problemas estructurales señalados. Por ahora es de solo lectura; la edición guiada llegará a continuación."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Ayuda"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"Acerca del Editor de configuración"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Cerrar"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Cómo usarlo"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Elige un archivo de configuración en el desplegable — printer.cfg está seleccionado de forma predeterminada."}},{t:0,b:{t:2,i:[{t:3}],s:"Explora sus secciones; haz clic en una para desplegar sus parámetros."}},{t:0,b:{t:2,i:[{t:3}],s:"Revisa el aviso de Validación por problemas estructurales como una sección duplicada."}},{t:0,b:{t:2,i:[{t:3}],s:"Cambia a Texto sin formato para leer el texto exacto del archivo."}}],topics:{sections:{title:{t:0,b:{t:2,i:[{t:3}],s:"Secciones y parámetros"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Una configuración de Klipper es una lista de bloques [section], cada uno con parámetros key: value. Este widget analiza cada sección — incluidas las que tienen un nombre como [tmc2209 stepper_x] — y enumera sus parámetros con su valor y cualquier comentario en línea. Los valores de varias líneas (como el gcode: de una macro) se conservan intactos."}}},includes:{title:{t:0,b:{t:2,i:[{t:3}],s:"Archivos incluidos"}},body:{t:0,b:{t:2,i:[{t:3}],s:"A menudo printer.cfg incorpora otros archivos con [include other.cfg] (o un patrón como [include configs/*.cfg]). Cada inclusión se muestra como su propia entrada; elige el archivo incluido en el desplegable para inspeccionar lo que define."}}},validation:{title:{t:0,b:{t:2,i:[{t:3}],s:"Validación"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Tras el análisis, la configuración se comprueba en busca de problemas estructurales que son erróneos independientemente del tipo de sección — un encabezado de sección duplicado, un nombre de sección vacío o un parámetro situado fuera de cualquier sección. Estos aparecen en el aviso de Validación; no modifican tu archivo."}}},saveConfig:{title:{t:0,b:{t:2,i:[{t:3}],s:"El bloque SAVE_CONFIG"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Klipper añade un bloque autogenerado al final de printer.cfg (tras el marcador #*#) cuando ejecutas SAVE_CONFIG — resultados de calibración como los offsets de PID y Z. Se muestra pero se marca como guardado automáticamente, y se excluye del recuento de secciones editables porque no deberías editarlo a mano."}}},readonly:{title:{t:0,b:{t:2,i:[{t:3}],s:"Solo lectura (por ahora)"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Esta primera versión solo lee y muestra la configuración — no se escribe nada en la impresora. La edición guiada con confirmación (con una copia de seguridad automática antes de cualquier guardado y un reinicio posterior) llegará en una actualización futura."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glosario"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{section:{term:{t:0,b:{t:2,i:[{t:3}],s:"Sección"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un bloque [header] que agrupa ajustes relacionados, p. ej. [stepper_x] o [extruder]."}}},parameter:{term:{t:0,b:{t:2,i:[{t:3}],s:"Parámetro"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Una línea key: value (o key = value) dentro de una sección, opcionalmente con un comentario # al final."}}},include:{term:{t:0,b:{t:2,i:[{t:3}],s:"[include]"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Una directiva que incorpora otro archivo de configuración en printer.cfg, de modo que los ajustes pueden repartirse entre varios archivos."}}},saveConfig:{term:{t:0,b:{t:2,i:[{t:3}],s:"SAVE_CONFIG"}},def:{t:0,b:{t:2,i:[{t:3}],s:"El bloque autogenerado (tras #*#) donde Klipper almacena los resultados de calibración — no lo edites a mano."}}}}},file:{label:{t:0,b:{t:2,i:[{t:3}],s:"Archivo de configuración"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"Selecciona un archivo…"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"Actualizar"}},loadingList:{t:0,b:{t:2,i:[{t:3}],s:"Cargando archivos…"}},emptyList:{t:0,b:{t:2,i:[{t:3}],s:"No se encontraron archivos de configuración en la impresora."}}},summary:{sections:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" secciones"}]}},params:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" parámetros"}]}},size:{t:0,b:{t:2,i:[{t:4,k:"kb"},{t:3,v:" KB"}]}}},validation:{title:{t:0,b:{t:2,i:[{t:3}],s:"Validación"}},clean:{t:0,b:{t:2,i:[{t:3}],s:"No se encontraron problemas estructurales."}},error:{t:0,b:{t:2,i:[{t:3}],s:"Error"}},warning:{t:0,b:{t:2,i:[{t:3}],s:"Advertencia"}}},view:{structured:{t:0,b:{t:2,i:[{t:3}],s:"Estructurado"}},raw:{t:0,b:{t:2,i:[{t:3}],s:"Texto sin formato"}},expandAll:{t:0,b:{t:2,i:[{t:3}],s:"Desplegar todo"}},collapseAll:{t:0,b:{t:2,i:[{t:3}],s:"Contraer todo"}}},section:{saveBadge:{t:0,b:{t:2,i:[{t:3}],s:"guardado automáticamente"}},noParams:{t:0,b:{t:2,i:[{t:3}],s:"(sin parámetros)"}},paramsCount:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" parámetros"}]}},paramHead:{t:0,b:{t:2,i:[{t:3}],s:"Parámetro"}},valueHead:{t:0,b:{t:2,i:[{t:3}],s:"Valor"}}},edit:{hint:{t:0,b:{t:2,i:[{t:3}],s:"Edita el texto sin formato de abajo y luego pulsa Guardar. Se crea una copia de seguridad con marca de tiempo antes de cualquier escritura."}}},save:{button:{t:0,b:{t:2,i:[{t:3}],s:"Guardar"}},saving:{t:0,b:{t:2,i:[{t:3}],s:"Guardando…"}},unsaved:{t:0,b:{t:2,i:[{t:3}],s:"Cambios sin guardar"}},revert:{t:0,b:{t:2,i:[{t:3}],s:"Revertir"}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"¿Guardar en la impresora?"}},confirmBody:{t:0,b:{t:2,i:[{t:3,v:"Esto sobrescribe "},{t:4,k:"file"},{t:3,v:" en la impresora. Primero se guarda una copia de seguridad con marca de tiempo, y se necesita un reinicio del firmware para aplicar el cambio."}]}},ack:{t:0,b:{t:2,i:[{t:3}],s:"Entiendo que esto escribe en la impresora"}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Guardar"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Cancelar"}},done:{t:0,b:{t:2,i:[{t:3,v:"Guardado. Copia de seguridad: "},{t:4,k:"backup"}]}},busy:{t:0,b:{t:2,i:[{t:3}],s:"Rechazado: la impresora está ocupada (imprimiendo o en pausa). Inténtalo de nuevo cuando esté inactiva."}},error:{t:0,b:{t:2,i:[{t:3}],s:"Error al guardar."}}},restart:{prompt:{t:0,b:{t:2,i:[{t:3}],s:"¿Reiniciar el firmware para aplicar tu cambio?"}},button:{t:0,b:{t:2,i:[{t:3}],s:"Reiniciar firmware"}},restarting:{t:0,b:{t:2,i:[{t:3}],s:"Reiniciando…"}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"¿Reiniciar el firmware?"}},confirmBody:{t:0,b:{t:2,i:[{t:3}],s:"FIRMWARE_RESTART recarga la configuración e interrumpe brevemente la impresora. Hazlo solo cuando esté inactiva."}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Reiniciar ahora"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"Cancelar"}},done:{t:0,b:{t:2,i:[{t:3}],s:"Reinicio del firmware solicitado."}},busy:{t:0,b:{t:2,i:[{t:3}],s:"Rechazado: la impresora está ocupada. Reinicia cuando esté inactiva."}},error:{t:0,b:{t:2,i:[{t:3}],s:"Error al reiniciar."}}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Leyendo la configuración…"}},error:{t:0,b:{t:2,i:[{t:3}],s:"No se pudo leer la configuración de la impresora."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"Reintentar"}}},catalog:{title:{t:0,b:{t:2,i:[{t:3}],s:"Añadir un bloque de config del catálogo"}},hint:{t:0,b:{t:2,i:[{t:3}],s:"Elige una pieza — su bloque Klipper exacto (run_current, sense_resistor y nombres de pin reales) se añade al archivo para revisarlo y guardarlo."}},drivers:{t:0,b:{t:2,i:[{t:3}],s:"Drivers"}},motors:{t:0,b:{t:2,i:[{t:3}],s:"Motores"}},boards:{t:0,b:{t:2,i:[{t:3}],s:"Placas"}},pickPlaceholder:{t:0,b:{t:2,i:[{t:3}],s:"Buscar en el catálogo…"}},inserted:{t:0,b:{t:2,i:[{t:3,v:"Bloque de "},{t:4,k:"name"},{t:3,v:" insertado — revísalo en Raw y guarda."}]}},noSnippet:{t:0,b:{t:2,i:[{t:3,v:"No hay bloque de config para "},{t:4,k:"name"},{t:3,v:"."}]}}},drift:{title:{t:0,b:{t:2,i:[{t:3}],s:"Lo que Klipper está ejecutando"}},pending:{t:0,b:{t:2,i:[{t:3}],s:"Klipper tiene cambios sin guardar (SAVE_CONFIG pendiente) — guardar este archivo ahora los sobrescribiría. Ejecuta SAVE_CONFIG en la consola primero."}},warningsTitle:{t:0,b:{t:2,i:[{t:3}],s:"Avisos de config de Klipper"}},count:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" valor(es) en disco difieren de lo que se ejecuta (editado sin FIRMWARE_RESTART):"}]}},adopt:{t:0,b:{t:2,i:[{t:3}],s:"adoptar en vivo"}}},pinDoctor:{title:{t:0,b:{t:2,i:[{t:3,v:"Doctor de pines — "},{t:4,k:"n"},{t:3,v:" hallazgo(s) de cableado"}]}},conflict:{t:0,b:{t:2,i:[{t:3}],s:"CONFLICTO"}},caveat:{t:0,b:{t:2,i:[{t:3}],s:"AVISO"}}}}};export{e as default};
